// InspirationGallery.jsx
// Place in frontend/src/InspirationGallery.jsx
// Public page showing anonymized past plans for inspiration

import { useState, useEffect } from "react";
import { supabase } from "./supabase";

const OCCASIONS = ["All", "Birthday", "Anniversary", "Valentine's Day", "Just Because", "Graduation", "Apology"];
const TONES = ["All", "Romantic", "Funny", "Luxury", "Minimal", "Emotional", "Adventurous"];

export default function InspirationGallery({ onUsePlan, onBack }) {
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [occasion, setOccasion] = useState("All");
  const [tone, setTone] = useState("All");
  const [expanded, setExpanded] = useState(null);

  useEffect(() => {
    fetchPlans();
  }, []);

  const fetchPlans = async () => {
    setLoading(true);
    const { data } = await supabase
      .from("plans")
      .select("id, occasion, tone, budget, city, plan_data, created_at")
      .not("plan_data", "is", null)
      .order("created_at", { ascending: false })
      .limit(50);
    setPlans(data || []);
    setLoading(false);
  };

  const filtered = plans.filter(p => {
    const matchOccasion = occasion === "All" || p.occasion === occasion;
    const matchTone = tone === "All" || p.tone === tone;
    return matchOccasion && matchTone;
  });

  const formatDate = (d) => new Date(d).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });

  return (
    <div style={{ maxWidth: "800px", margin: "0 auto", padding: "1.5rem 1rem 4rem" }}>

      {/* Header */}
      <div style={{ marginBottom: "1.5rem" }}>
        <button onClick={onBack} style={{ background: "none", border: "none", fontSize: "13px", color: "#999", cursor: "pointer", marginBottom: "8px", padding: 0 }}>
          ← Back
        </button>
        <h1 style={{ fontFamily: "'Playfair Display', serif", fontSize: "26px", fontWeight: "500", marginBottom: "6px" }}>
          Surprise inspiration
        </h1>
        <p style={{ fontSize: "14px", color: "#999" }}>
          Real plans created by others — use them as inspiration or as a starting point.
        </p>
      </div>

      {/* Filters */}
      <div style={{ marginBottom: "1.25rem" }}>
        <div style={{ fontSize: "12px", color: "#999", marginBottom: "8px", fontWeight: "500", textTransform: "uppercase", letterSpacing: "0.06em" }}>Occasion</div>
        <div className="pill-group" style={{ marginBottom: "12px" }}>
          {OCCASIONS.map(o => (
            <span key={o} className={`pill ${occasion === o ? "selected" : ""}`} onClick={() => setOccasion(o)}>{o}</span>
          ))}
        </div>
        <div style={{ fontSize: "12px", color: "#999", marginBottom: "8px", fontWeight: "500", textTransform: "uppercase", letterSpacing: "0.06em" }}>Vibe</div>
        <div className="pill-group">
          {TONES.map(t => (
            <span key={t} className={`pill ${tone === t ? "selected" : ""}`} onClick={() => setTone(t)}>{t}</span>
          ))}
        </div>
      </div>

      {/* Count */}
      <div style={{ fontSize: "13px", color: "#999", marginBottom: "1rem" }}>
        {filtered.length} plans found
      </div>

      {/* Loading */}
      {loading && (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px" }}>
          {[1,2,3,4].map(i => <div key={i} className="myplans-skeleton" style={{ height: "160px" }} />)}
        </div>
      )}

      {/* Empty */}
      {!loading && filtered.length === 0 && (
        <div style={{ textAlign: "center", padding: "3rem", color: "#999" }}>
          <div style={{ fontSize: "32px", marginBottom: "1rem" }}>✨</div>
          <p>No plans yet for this filter.</p>
          <button className="btn-next" style={{ marginTop: "1rem", width: "auto", padding: "10px 24px" }} onClick={onBack}>
            Create the first one
          </button>
        </div>
      )}

      {/* Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px" }}>
        {filtered.map(p => {
          const data = p.plan_data || {};
          const isExpanded = expanded === p.id;
          return (
            <div
              key={p.id}
              style={{
                background: "#fff",
                border: isExpanded ? "0.5px solid #7F77DD" : "0.5px solid #eee",
                borderRadius: "12px",
                padding: "1.25rem",
                cursor: "pointer",
                transition: "all 0.2s",
                gridColumn: isExpanded ? "1 / -1" : "auto",
              }}
              onClick={() => setExpanded(isExpanded ? null : p.id)}
            >
              {/* Badges */}
              <div style={{ display: "flex", gap: "6px", flexWrap: "wrap", marginBottom: "10px" }}>
                {p.occasion && (
                  <span style={{ fontSize: "11px", fontWeight: "500", padding: "2px 8px", borderRadius: "10px", background: "#EEEDFE", color: "#534AB7" }}>
                    {p.occasion}
                  </span>
                )}
                {p.tone && (
                  <span style={{ fontSize: "11px", fontWeight: "500", padding: "2px 8px", borderRadius: "10px", background: "#E1F5EE", color: "#0F6E56" }}>
                    {p.tone}
                  </span>
                )}
                {p.budget && (
                  <span style={{ fontSize: "11px", padding: "2px 8px", borderRadius: "10px", background: "#f5f5f5", color: "#888" }}>
                    Rs {Number(p.budget).toLocaleString("en-IN")}
                  </span>
                )}
              </div>

              {/* Idea */}
              <div style={{ fontSize: "15px", fontWeight: "500", color: "#111", marginBottom: "8px", lineHeight: "1.4" }}>
                {data.idea || "Surprise plan"}
              </div>

              {/* Message preview */}
              <p style={{ fontSize: "13px", color: "#888", lineHeight: "1.6", marginBottom: "10px" }}>
                {data.message
                  ? (data.message.length > 80 ? data.message.slice(0, 80) + "..." : data.message)
                  : ""}
              </p>

              {/* Expanded content */}
              {isExpanded && (
                <div style={{ borderTop: "0.5px solid #eee", paddingTop: "16px", marginTop: "8px" }}>

                  {/* Timeline */}
                  {data.timeline && (
                    <div style={{ marginBottom: "16px" }}>
                      {[
                        { label: "Before", color: "#7F77DD", items: data.timeline.before || [] },
                        { label: "On the day", color: "#1D9E75", items: data.timeline.during || [] },
                        { label: "After", color: "#BA7517", items: data.timeline.after || [] },
                      ].map(s => s.items.length > 0 && (
                        <div key={s.label} style={{ marginBottom: "12px" }}>
                          <div style={{ fontSize: "11px", fontWeight: "600", color: s.color, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: "6px" }}>
                            {s.label}
                          </div>
                          {s.items.map((item, i) => (
                            <div key={i} style={{ fontSize: "13px", color: "#555", paddingLeft: "12px", borderLeft: `2px solid ${s.color}`, marginBottom: "4px", lineHeight: "1.5" }}>
                              {item.replace(/^[-•]\s*/, "")}
                            </div>
                          ))}
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Actions */}
                  <div style={{ display: "flex", gap: "8px" }}>
                    <button
                      onClick={(e) => { e.stopPropagation(); onUsePlan && onUsePlan(p); }}
                      className="btn-next"
                      style={{ flex: 1, padding: "10px" }}
                    >
                      Use this as inspiration
                    </button>
                    <button
                      onClick={(e) => { e.stopPropagation(); setExpanded(null); }}
                      className="btn-back"
                      style={{ padding: "10px 16px" }}
                    >
                      Close
                    </button>
                  </div>
                </div>
              )}

              {/* Footer */}
              {!isExpanded && (
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span style={{ fontSize: "11px", color: "#bbb" }}>{formatDate(p.created_at)}</span>
                  <span style={{ fontSize: "12px", color: "#7F77DD" }}>View plan →</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Bottom CTA */}
      {!loading && filtered.length > 0 && (
        <div style={{
          marginTop: "2rem", textAlign: "center", padding: "1.5rem",
          borderTop: "0.5px solid #eee",
        }}>
          <p style={{ fontSize: "14px", color: "#999", marginBottom: "12px" }}>
            Don't see what you're looking for?
          </p>
          <button className="btn-generate" style={{ padding: "12px 32px" }} onClick={onBack}>
            Create a custom plan
          </button>
        </div>
      )}
    </div>
  );
}

import { useState } from "react";

const ACTIVITY_TYPES = [
  { id: "board_games", emoji: "🎲", name: "Board Game Night", desc: "Curated games, no experience needed. Strategy, laughter, and zero awkward silences.", energy: "low", color: "#7B6EE8", bg: "rgba(123,110,232,0.08)" },
  { id: "coffee_trail", emoji: "☕", name: "Quiet Coffee Trail", desc: "Three indie cafés, one afternoon. The kind of conversation you actually remember.", energy: "low", color: "#D4AF37", bg: "rgba(212,175,55,0.08)" },
  { id: "art_workshop", emoji: "🎨", name: "Art Workshop", desc: "Pottery, watercolour, or collage. Work side by side. Take home what you make.", energy: "low", color: "#E85D75", bg: "rgba(232,93,117,0.08)" },
  { id: "nature_walk", emoji: "🌿", name: "Nature Walk", desc: "Cubbon Park at golden hour. Birdsong, fresh air, and an ending chai.", energy: "medium", color: "#1DB375", bg: "rgba(29,179,117,0.08)" },
  { id: "book_swap", emoji: "📚", name: "Book Swap", desc: "Bring a book you love. Leave with one you've never heard of. Talk about both.", energy: "low", color: "#D4AF37", bg: "rgba(212,175,55,0.08)" },
  { id: "cook_together", emoji: "🍳", name: "Cook Together", desc: "One kitchen, one dish, four strangers. The meal is just the excuse to connect.", energy: "medium", color: "#E85D75", bg: "rgba(232,93,117,0.08)" },
];

const STEPS = [
  { n: "01", icon: "🧭", title: "Tell us your vibe", desc: "Energy level, interests, what makes a perfect Saturday for you." },
  { n: "02", icon: "🤖", title: "AI matches you", desc: "We find 2–3 people in Bangalore with overlapping energy and interests." },
  { n: "03", icon: "🎁", title: "Mystery plan created", desc: "An AI-generated secret itinerary — venue revealed 30 min before." },
  { n: "04", icon: "✨", title: "Show up, connect", desc: "Arrive alone. Leave with people you actually want to see again." },
];

const STATS = [
  ["347", "Connections made"],
  ["89", "Events this month"],
  ["4", "People max per event"],
  ["4.8★", "Average rating"],
];

export default function IntrovertLanding({ onJoin, onBrowse, onCreateProfile }) {
  const [hoveredActivity, setHoveredActivity] = useState(null);

  return (
    <div style={{ minHeight: "100vh", background: "#080808", color: "#fff", fontFamily: "'DM Sans', sans-serif", overflowX: "hidden" }}>

      {/* BG */}
      <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0 }}>
        <div style={{ position: "absolute", width: "800px", height: "800px", borderRadius: "50%", top: "-300px", right: "-200px", background: "radial-gradient(circle, rgba(29,179,117,0.07) 0%, transparent 65%)", animation: "orb1 14s ease-in-out infinite" }} />
        <div style={{ position: "absolute", width: "600px", height: "600px", borderRadius: "50%", bottom: "-200px", left: "-150px", background: "radial-gradient(circle, rgba(123,110,232,0.08) 0%, transparent 65%)", animation: "orb2 18s ease-in-out infinite" }} />
      </div>

      {/* HERO */}
      <section style={{ position: "relative", zIndex: 10, maxWidth: "1200px", margin: "0 auto", padding: "clamp(60px, 10vh, 120px) clamp(24px, 5vw, 80px) clamp(60px, 8vh, 100px)", textAlign: "center" }}>

        <div style={{ display: "inline-flex", alignItems: "center", gap: "12px", marginBottom: "36px", padding: "6px 20px", border: "1px solid rgba(29,179,117,0.25)", borderRadius: "40px", background: "rgba(29,179,117,0.06)" }}>
          <div style={{ width: "6px", height: "6px", borderRadius: "50%", background: "#1DB375", animation: "pulse 2s infinite" }} />
          <span style={{ fontSize: "11px", letterSpacing: "0.22em", color: "#1DB375", textTransform: "uppercase" }}>New · Bangalore · Beta</span>
        </div>

        <h1 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(48px, 6vw, 96px)", fontWeight: "300", lineHeight: "1.0", letterSpacing: "-0.02em", marginBottom: "28px" }}>
          <span style={{ display: "block", color: "#fff" }}>Meet your people.</span>
          <span style={{ display: "block", color: "#1DB375", fontStyle: "italic" }}>The introvert way.</span>
        </h1>

        <p style={{ fontSize: "clamp(15px, 1.8vw, 18px)", color: "rgba(255,255,255,0.38)", lineHeight: "1.9", maxWidth: "560px", margin: "0 auto 56px", fontWeight: "300" }}>
          You moved to Bangalore. You have work friends. What you're missing are real connections — people who enjoy the same quiet, meaningful, slightly nerdy things you do.
        </p>

        <div style={{ display: "flex", gap: "16px", justifyContent: "center", flexWrap: "wrap" }}>
          <button onClick={onCreateProfile} style={{ padding: "16px 48px", background: "#1DB375", border: "none", color: "#080808", fontSize: "13px", letterSpacing: "0.14em", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", fontWeight: "700", cursor: "pointer", transition: "all 0.3s" }}
            onMouseEnter={e => { e.target.style.background = "#22d68a"; e.target.style.transform = "translateY(-3px)"; e.target.style.boxShadow = "0 12px 32px rgba(29,179,117,0.3)"; }}
            onMouseLeave={e => { e.target.style.background = "#1DB375"; e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "none"; }}
          >Find my people →</button>
          <button onClick={onBrowse} style={{ padding: "16px 32px", background: "none", border: "1px solid rgba(255,255,255,0.15)", color: "rgba(255,255,255,0.6)", fontSize: "13px", letterSpacing: "0.1em", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", cursor: "pointer", transition: "all 0.2s" }}
            onMouseEnter={e => { e.target.style.borderColor = "rgba(255,255,255,0.4)"; e.target.style.color = "#fff"; }}
            onMouseLeave={e => { e.target.style.borderColor = "rgba(255,255,255,0.15)"; e.target.style.color = "rgba(255,255,255,0.6)"; }}
          >Browse events</button>
        </div>

        {/* Stats */}
        <div style={{ display: "flex", justifyContent: "center", gap: "clamp(28px, 5vw, 64px)", marginTop: "72px", paddingTop: "48px", borderTop: "1px solid rgba(255,255,255,0.06)", flexWrap: "wrap" }}>
          {STATS.map(([n, l]) => (
            <div key={l} style={{ textAlign: "center" }}>
              <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(24px, 3vw, 36px)", fontWeight: "300", color: "#1DB375" }}>{n}</div>
              <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.25)", letterSpacing: "0.14em", textTransform: "uppercase", marginTop: "6px" }}>{l}</div>
            </div>
          ))}
        </div>
      </section>

      {/* HOW IT WORKS */}
      <section style={{ position: "relative", zIndex: 10, background: "rgba(255,255,255,0.015)", borderTop: "1px solid rgba(255,255,255,0.05)", borderBottom: "1px solid rgba(255,255,255,0.05)", padding: "clamp(60px, 8vh, 100px) clamp(24px, 5vw, 80px)" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: "64px" }}>
            <div style={{ fontSize: "10px", letterSpacing: "0.3em", color: "#1DB375", textTransform: "uppercase", marginBottom: "16px", opacity: 0.8 }}>How it works</div>
            <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(32px, 4vw, 56px)", fontWeight: "300" }}>
              Four steps to <span style={{ color: "#1DB375", fontStyle: "italic" }}>real connections</span>
            </h2>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "2px", background: "rgba(255,255,255,0.05)" }} className="ia-steps-grid">
            {STEPS.map((s) => (
              <div key={s.n} style={{ background: "#080808", padding: "clamp(28px, 3vw, 44px) clamp(20px, 2.5vw, 36px)", transition: "background 0.3s" }}
                onMouseEnter={e => e.currentTarget.style.background = "#0d0d0d"}
                onMouseLeave={e => e.currentTarget.style.background = "#080808"}
              >
                <div style={{ fontSize: "10px", letterSpacing: "0.28em", color: "#1DB375", marginBottom: "20px", opacity: 0.65 }}>{s.n}</div>
                <div style={{ fontSize: "28px", marginBottom: "16px" }}>{s.icon}</div>
                <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(18px, 2vw, 22px)", fontWeight: "300", color: "#fff", marginBottom: "12px" }}>{s.title}</div>
                <p style={{ fontSize: "13px", color: "rgba(255,255,255,0.35)", lineHeight: "1.85" }}>{s.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ACTIVITY TYPES */}
      <section style={{ position: "relative", zIndex: 10, maxWidth: "1200px", margin: "0 auto", padding: "clamp(60px, 8vh, 100px) clamp(24px, 5vw, 80px)" }}>
        <div style={{ textAlign: "center", marginBottom: "64px" }}>
          <div style={{ fontSize: "10px", letterSpacing: "0.3em", color: "#1DB375", textTransform: "uppercase", marginBottom: "16px", opacity: 0.8 }}>What we do</div>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(32px, 4vw, 56px)", fontWeight: "300" }}>
            Six kinds of <span style={{ color: "#1DB375", fontStyle: "italic" }}>low-pressure magic</span>
          </h2>
          <p style={{ fontSize: "14px", color: "rgba(255,255,255,0.3)", marginTop: "16px", lineHeight: 1.8, maxWidth: "480px", margin: "16px auto 0" }}>
            All activities are chosen to be comfortable for introverts — structured enough to kill awkwardness, open enough for real conversation.
          </p>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "2px", background: "rgba(255,255,255,0.05)" }} className="ia-activities-grid">
          {ACTIVITY_TYPES.map((act) => (
            <div key={act.id}
              onMouseEnter={() => setHoveredActivity(act.id)}
              onMouseLeave={() => setHoveredActivity(null)}
              onClick={onBrowse}
              style={{
                background: hoveredActivity === act.id ? act.bg : "#080808",
                padding: "clamp(28px, 3vw, 44px)", cursor: "pointer",
                transition: "all 0.35s ease", position: "relative", overflow: "hidden",
                border: hoveredActivity === act.id ? `1px solid ${act.color}30` : "1px solid transparent",
              }}
            >
              <div style={{ fontSize: "40px", marginBottom: "20px" }}>{act.emoji}</div>
              <div style={{ fontSize: "clamp(16px, 2vw, 19px)", fontWeight: "500", color: hoveredActivity === act.id ? act.color : "#fff", marginBottom: "10px", transition: "color 0.3s" }}>{act.name}</div>
              <div style={{ display: "inline-block", fontSize: "10px", letterSpacing: "0.14em", color: act.color, textTransform: "uppercase", marginBottom: "14px", padding: "3px 10px", border: `1px solid ${act.color}40`, borderRadius: "20px", background: `${act.color}10` }}>
                {act.energy === "low" ? "🌙 Chill" : "⚡ Moderate"} energy
              </div>
              <p style={{ fontSize: "13px", color: "rgba(255,255,255,0.38)", lineHeight: "1.85" }}>{act.desc}</p>
              <div style={{ marginTop: "20px", fontSize: "11px", letterSpacing: "0.12em", color: hoveredActivity === act.id ? act.color : "rgba(255,255,255,0.25)", textTransform: "uppercase", transition: "color 0.3s" }}>
                See events →
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* WHY THIS WORKS */}
      <section style={{ position: "relative", zIndex: 10, background: "rgba(29,179,117,0.04)", borderTop: "1px solid rgba(29,179,117,0.1)", borderBottom: "1px solid rgba(29,179,117,0.1)", padding: "clamp(60px, 8vh, 100px) clamp(24px, 5vw, 80px)" }}>
        <div style={{ maxWidth: "1000px", margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", gap: "80px", alignItems: "center" }} className="ia-why-grid">
          <div>
            <div style={{ fontSize: "10px", letterSpacing: "0.3em", color: "#1DB375", textTransform: "uppercase", marginBottom: "20px", opacity: 0.8 }}>Designed for introverts</div>
            <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(32px, 4vw, 52px)", fontWeight: "300", lineHeight: "1.1", marginBottom: "20px" }}>
              Not a networking event.<br /><span style={{ color: "#1DB375", fontStyle: "italic" }}>Not a dating app.</span>
            </h2>
            <p style={{ fontSize: "14px", color: "rgba(255,255,255,0.38)", lineHeight: "1.9", marginBottom: "32px" }}>
              We designed every part of this for people who find "small talk" draining. The activities give you something to do. The AI picks people with genuinely overlapping interests. The group caps at 4 — so it never feels like a crowd.
            </p>
            <button onClick={onCreateProfile} style={{ padding: "14px 36px", background: "#1DB375", border: "none", color: "#080808", fontSize: "12px", letterSpacing: "0.14em", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", fontWeight: "700", cursor: "pointer", transition: "all 0.25s" }}
              onMouseEnter={e => { e.target.style.background = "#22d68a"; e.target.style.transform = "translateY(-2px)"; }}
              onMouseLeave={e => { e.target.style.background = "#1DB375"; e.target.style.transform = "translateY(0)"; }}
            >Build my profile →</button>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
            {[
              ["🔒", "Max 4 people", "Every event is capped at 4 people. Intimate by design."],
              ["🎯", "Matched by vibe", "AI pairs you based on energy, interests, and conversational style."],
              ["🎁", "Mystery venue", "Location revealed 30 minutes before. The mystery is part of the fun."],
              ["🛡️", "Safety first", "All profiles verified. One-tap reporting. Real humans review events."],
            ].map(([icon, title, desc]) => (
              <div key={title} style={{ display: "flex", gap: "16px", padding: "20px", border: "1px solid rgba(29,179,117,0.12)", background: "rgba(29,179,117,0.03)", transition: "all 0.2s" }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = "rgba(29,179,117,0.3)"; e.currentTarget.style.background = "rgba(29,179,117,0.06)"; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "rgba(29,179,117,0.12)"; e.currentTarget.style.background = "rgba(29,179,117,0.03)"; }}
              >
                <span style={{ fontSize: "22px", flexShrink: 0, lineHeight: 1.3 }}>{icon}</span>
                <div>
                  <div style={{ fontSize: "14px", fontWeight: "600", color: "rgba(255,255,255,0.85)", marginBottom: "4px" }}>{title}</div>
                  <div style={{ fontSize: "13px", color: "rgba(255,255,255,0.35)", lineHeight: "1.7" }}>{desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section style={{ position: "relative", zIndex: 10, maxWidth: "700px", margin: "0 auto", padding: "clamp(80px, 10vh, 120px) clamp(24px, 5vw, 40px)", textAlign: "center" }}>
        <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(36px, 4.5vw, 64px)", fontWeight: "300", lineHeight: "1.1", marginBottom: "20px" }}>
          You don't have to<br />explore alone.
        </h2>
        <p style={{ fontSize: "15px", color: "rgba(255,255,255,0.35)", lineHeight: 1.85, marginBottom: "48px" }}>
          Hundreds of people like you are in Bangalore right now, looking for the same thing. The only difference is they signed up.
        </p>
        <button onClick={onCreateProfile} style={{ padding: "18px 60px", background: "#1DB375", border: "none", color: "#080808", fontSize: "13px", letterSpacing: "0.16em", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", fontWeight: "700", cursor: "pointer", transition: "all 0.3s" }}
          onMouseEnter={e => { e.target.style.background = "#22d68a"; e.target.style.transform = "translateY(-3px)"; e.target.style.boxShadow = "0 12px 32px rgba(29,179,117,0.3)"; }}
          onMouseLeave={e => { e.target.style.background = "#1DB375"; e.target.style.transform = "translateY(0)"; e.target.style.boxShadow = "none"; }}
        >Find my people — it's free →</button>
        <div style={{ marginTop: "20px", fontSize: "12px", color: "rgba(255,255,255,0.2)" }}>Free to join · Bangalore only · ₹99 deposit for events</div>
      </section>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;1,300&family=DM+Sans:wght@300;400;500;600;700&display=swap');
        @keyframes orb1 { 0%,100%{transform:translate(0,0) scale(1)} 40%{transform:translate(40px,-60px) scale(1.08)} 70%{transform:translate(-30px,30px) scale(0.95)} }
        @keyframes orb2 { 0%,100%{transform:translate(0,0) scale(1)} 35%{transform:translate(-50px,40px) scale(1.1)} 65%{transform:translate(25px,-25px) scale(0.92)} }
        @keyframes pulse { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.4;transform:scale(0.7)} }
        * { box-sizing: border-box; }
        @media (max-width: 900px) {
          .ia-steps-grid { grid-template-columns: 1fr 1fr !important; }
          .ia-activities-grid { grid-template-columns: 1fr 1fr !important; }
          .ia-why-grid { grid-template-columns: 1fr !important; gap: 40px !important; }
        }
        @media (max-width: 600px) {
          .ia-steps-grid { grid-template-columns: 1fr !important; }
          .ia-activities-grid { grid-template-columns: 1fr !important; }
        }
      `}</style>
    </div>
  );
}

// MatchedVendors.jsx — Auto-matched vendors from AI plan
import { motion } from "framer-motion";

export default function MatchedVendors({ vendors, onBrowse }) {
  if (!vendors || vendors.length === 0) return null;

  const openWhatsApp = (v) => {
    const num = (v.whatsapp || v.phone || "").replace(/\D/g, "");
    const msg = encodeURIComponent(`Hi ${v.name}! I found you on AI Surprise Planner and I'd love to book for a special occasion.`);
    window.open(`https://wa.me/${num}?text=${msg}`, "_blank");
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.2 }}
      style={{ marginBottom: "14px" }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "12px" }}>
        <div style={{ flex: 1, height: "1px", background: "rgba(212,175,55,0.15)" }} />
        <div style={{ fontSize: "11px", fontWeight: "700", color: "var(--gold)", textTransform: "uppercase", letterSpacing: "0.12em", opacity: 0.8, whiteSpace: "nowrap" }}>
          ✦ Matched for your plan
        </div>
        <div style={{ flex: 1, height: "1px", background: "rgba(212,175,55,0.15)" }} />
      </div>

      <motion.div
        style={{ display: "flex", flexDirection: "column", gap: "8px" }}
        initial="hidden" animate="visible"
        variants={{ visible: { transition: { staggerChildren: 0.1 } } }}
      >
        {vendors.map((v, i) => (
          <motion.div
            key={i}
            variants={{ hidden: { opacity: 0, x: -16 }, visible: { opacity: 1, x: 0 } }}
            transition={{ duration: 0.4 }}
            style={{
              background: "var(--glass)",
              border: v.is_featured ? "1px solid rgba(212,175,55,0.3)" : "1px solid var(--glass-border)",
              borderRadius: "12px",
              padding: "14px 16px",
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: "12px",
              backdropFilter: "blur(16px)",
            }}
          >
            <div style={{ flex: 1 }}>
              <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "3px" }}>
                {v.is_featured && <span style={{ fontSize: "9px", fontWeight: "700", color: "var(--gold)", background: "var(--gold-bg)", border: "1px solid rgba(212,175,55,0.3)", padding: "2px 7px", borderRadius: "20px", letterSpacing: "0.08em", textTransform: "uppercase" }}>Featured</span>}
                <span style={{ fontSize: "14px", fontWeight: "500", color: "var(--text-1)" }}>{v.name}</span>
              </div>
              <div style={{ fontSize: "12px", color: "var(--text-3)" }}>
                {v.category}{v.city ? ` · ${v.city}` : ""}{v.min_budget ? ` · from ₹${Number(v.min_budget).toLocaleString("en-IN")}` : ""}
              </div>
            </div>
            {(v.whatsapp || v.phone) && (
              <button
                onClick={() => openWhatsApp(v)}
                style={{
                  padding: "8px 14px", borderRadius: "20px", border: "none",
                  background: "#25D366", color: "#fff", fontSize: "12px",
                  fontWeight: "600", cursor: "pointer", flexShrink: 0, fontFamily: "inherit",
                }}
              >
                WhatsApp
              </button>
            )}
          </motion.div>
        ))}
      </motion.div>

      {onBrowse && (
        <button
          onClick={onBrowse}
          style={{ width: "100%", padding: "10px", marginTop: "8px", borderRadius: "8px", background: "transparent", border: "1px solid var(--glass-border)", color: "var(--text-2)", fontSize: "12px", cursor: "pointer", fontFamily: "inherit", letterSpacing: "0.04em" }}
        >
          See all vendors →
        </button>
      )}
    </motion.div>
  );
}

